import json
import enum

class EnumEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, enum.Enum):
            return obj.value
        return json.JSONEncoder.default(self, obj)

if __name__ == '__main__':
    # Örnek kullanım
    class MyColor(enum.Enum):
        RED = 1
        GREEN = 2
        BLUE = 3

    class Status(enum.Enum):
        ACTIVE = "active"
        INACTIVE = "inactive"
        PENDING = "pending"

    data = {
        "primary_color": MyColor.RED,
        "secondary_color": MyColor.GREEN,
        "current_status": Status.ACTIVE,
        "items": [
            {"id": 1, "color": MyColor.BLUE, "status": Status.PENDING},
            {"id": 2, "color": MyColor.RED, "status": Status.INACTIVE}
        ],
        "message": "Hello World"
    }

    # Custom encoder ile serialize et
    json_output = json.dumps(data, cls=EnumEncoder, indent=4)
    print(json_output)

    # Doğrudan bir Enum objesini serialize etme
    print("\nTek bir Enum objesi:")
    print(json.dumps(MyColor.RED, cls=EnumEncoder, indent=4))
    print(json.dumps(Status.PENDING, cls=EnumEncoder, indent=4))
